import json

baseline = json.load(open('baseline-packages.json'))
after = json.load(open('after-cpm-packages.json'))

def extract(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            for pkg in fw.get('topLevelPackages', []):
                key = (name, fw['framework'], pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))
changes = []
unchanged = []
for k in all_keys:
    bv = b.get(k)
    av = a.get(k)
    proj, fw, pkg = k
    if bv != av:
        changes.append((proj, fw, pkg, bv or '(none)', av or '(none)'))
    else:
        unchanged.append((proj, fw, pkg, av))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'  {c[0]} ({c[1]}) | {c[2]} | {c[3]} -> {c[4]}')
else:
    print('  None')

print()
print(f'=== UNCHANGED: {len(unchanged)} packages ===')
for u in unchanged:
    print(f'  {u[0]} ({u[1]}) | {u[2]} | {u[3]}')
"

